// Filter for markets created in the last 2 hours with >$10K volume
const TWO_HOURS_MS = 2 * 60 * 60 * 1000;
const cutoff = Date.now() - TWO_HOURS_MS;
const MIN_VOLUME = 10000;
const WEBHOOK_URL = $env.WEBHOOK_URL || 'http://localhost:3000';

const marketsRaw = $input.first().json;
const markets = Array.isArray(marketsRaw) ? marketsRaw : [marketsRaw];

// Use workflow static data for deduplication
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenMarkets) {
  staticData.seenMarkets = {};
}

const results = [];

for (const market of markets) {
  const startDate = new Date(market.startDate || market.createdAt || 0).getTime();
  const volume = parseFloat(market.volume || '0');

  // Skip if we've already alerted on this market
  if (staticData.seenMarkets[market.conditionId]) continue;

  if (startDate > cutoff && volume > MIN_VOLUME) {
    const hoursOld = ((Date.now() - startDate) / (60 * 60 * 1000)).toFixed(1);
    const outcomePrices = JSON.parse(market.outcomePrices || '[0, 0]');
    const clobTokenIds = JSON.parse(market.clobTokenIds || '["", ""]');
    const currentPrice = parseFloat(outcomePrices[0]) || 0;

    // Mark as seen
    staticData.seenMarkets[market.conditionId] = Date.now();

    results.push({
      json: {
        webhookUrl: WEBHOOK_URL + '/api/alert',
        payload: {
          category: 'new_markets',
          title: `New market: "${market.question}" -- $${Math.round(volume).toLocaleString()} volume in first ${hoursOld}h`,
          body: `New market just opened: "${market.question}". Already has $${Math.round(volume).toLocaleString()} in volume after ${hoursOld} hours. Current YES price: $${currentPrice.toFixed(2)}.`,
          market: {
            conditionId: market.conditionId,
            question: market.question || 'Unknown market',
            tokenId: clobTokenIds[0] || '',
            currentPrice: currentPrice
          },
          urgent: false,
          metadata: {
            volume: volume,
            hoursOld: parseFloat(hoursOld),
            startDate: market.startDate
          }
        }
      }
    });
  }
}

// Clean up old entries from seen markets (older than 24h)
const dayAgo = Date.now() - 24 * 60 * 60 * 1000;
for (const [id, timestamp] of Object.entries(staticData.seenMarkets)) {
  if (timestamp < dayAgo) {
    delete staticData.seenMarkets[id];
  }
}

if (results.length === 0) {
  return [];
}

return results;
